-- Add new schema named "bronze_history"
CREATE SCHEMA IF NOT EXISTS "bronze_history";
-- Create "aws_ec2_instance_tags_history" table
CREATE TABLE "bronze_history"."aws_ec2_instance_tags_history" (
  "history_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "instance_history_id" bigint NOT NULL,
  "valid_from" timestamptz NOT NULL,
  "valid_to" timestamptz NULL,
  "key" character varying NULL,
  "value" character varying NULL,
  PRIMARY KEY ("history_id")
);
-- Create index "bronzehistoryawsec2instancetag_instance_history_id" to table: "aws_ec2_instance_tags_history"
CREATE INDEX "bronzehistoryawsec2instancetag_instance_history_id" ON "bronze_history"."aws_ec2_instance_tags_history" ("instance_history_id");
-- Create index "bronzehistoryawsec2instancetag_valid_from" to table: "aws_ec2_instance_tags_history"
CREATE INDEX "bronzehistoryawsec2instancetag_valid_from" ON "bronze_history"."aws_ec2_instance_tags_history" ("valid_from");
-- Create index "bronzehistoryawsec2instancetag_valid_to" to table: "aws_ec2_instance_tags_history"
CREATE INDEX "bronzehistoryawsec2instancetag_valid_to" ON "bronze_history"."aws_ec2_instance_tags_history" ("valid_to");
-- Create "aws_ec2_instances_history" table
CREATE TABLE "bronze_history"."aws_ec2_instances_history" (
  "history_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "valid_from" timestamptz NOT NULL,
  "valid_to" timestamptz NULL,
  "collected_at" timestamptz NOT NULL,
  "first_collected_at" timestamptz NOT NULL,
  "resource_id" character varying NOT NULL,
  "name" character varying NULL,
  "instance_type" character varying NULL,
  "state" character varying NULL,
  "vpc_id" character varying NULL,
  "subnet_id" character varying NULL,
  "private_ip_address" character varying NULL,
  "public_ip_address" character varying NULL,
  "ami_id" character varying NULL,
  "key_name" character varying NULL,
  "launch_time" timestamptz NULL,
  "platform" character varying NULL,
  "architecture" character varying NULL,
  "security_groups_json" jsonb NULL,
  "account_id" character varying NOT NULL,
  "region" character varying NOT NULL,
  PRIMARY KEY ("history_id")
);
-- Create index "bronzehistoryawsec2instance_account_id" to table: "aws_ec2_instances_history"
CREATE INDEX "bronzehistoryawsec2instance_account_id" ON "bronze_history"."aws_ec2_instances_history" ("account_id");
-- Create index "bronzehistoryawsec2instance_collected_at" to table: "aws_ec2_instances_history"
CREATE INDEX "bronzehistoryawsec2instance_collected_at" ON "bronze_history"."aws_ec2_instances_history" ("collected_at");
-- Create index "bronzehistoryawsec2instance_region" to table: "aws_ec2_instances_history"
CREATE INDEX "bronzehistoryawsec2instance_region" ON "bronze_history"."aws_ec2_instances_history" ("region");
-- Create index "bronzehistoryawsec2instance_resource_id_valid_from" to table: "aws_ec2_instances_history"
CREATE INDEX "bronzehistoryawsec2instance_resource_id_valid_from" ON "bronze_history"."aws_ec2_instances_history" ("resource_id", "valid_from");
-- Create index "bronzehistoryawsec2instance_valid_to" to table: "aws_ec2_instances_history"
CREATE INDEX "bronzehistoryawsec2instance_valid_to" ON "bronze_history"."aws_ec2_instances_history" ("valid_to");
